import React from 'react';
import { H4 } from '../../AbstractElements';

export const AreaColumns = [
    {
        name: <H4>Area</H4>,
        selector: row => row.Area,
        sortable: true,
        width:'400px',
        sortFunction: (a, b) => {
            const nameA = a?.Area?.toString().toLowerCase() || '';
            const nameB = b?.Area?.toString().toLowerCase() || '';
            if (nameA < nameB) return -1;
            if (nameA > nameB) return 1;
            return 0;
        }
    },
    {
        name: <H4>Area Code</H4>,
        selector: row => row.AreaCode,
        sortable: true,
        width:'250px',
        sortFunction: (a, b) => {
            const nameA = a?.AreaCode?.toString().toLowerCase() || '';
            const nameB = b?.AreaCode?.toString().toLowerCase() || '';
            if (nameA < nameB) return -1;
            if (nameA > nameB) return 1;
            return 0;
        }
    },
    {
        name: <H4>Action</H4>,
        selector: row => row.action,
        width:'200px',
        center: true,
    },
];

